#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        qsort(A, N, sizeof(int), compare);
        long long sum = 0;
        for (int i = 0; i < N / 2; i++) {
            sum += abs(A[i] - A[N - 1 - i]);
        }
        printf("%lld\n", sum);
    }
    return 0;
}

