const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextInt() {
    return parseInt(lines[idx++]);
}

function nextIntArray() {
    return lines[idx++].split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let N = nextInt();
    let A = nextIntArray();
    A.sort((a, b) => a - b);
    let sum = 0;
    for (let i = 0; i < N / 2; i++) {
        sum += Math.abs(A[i] - A[N - 1 - i]);
    }
    console.log(sum);
}
